const API_BASE_URL = 'http://localhost:5000/api';

const getToken = () => localStorage.getItem('token');

const api = {
  // Friends
  getFriends: async () => {
    const response = await fetch(`${API_BASE_URL}/friends`, {
      headers: { 'Authorization': `Bearer ${getToken()}` }
    });
    if (!response.ok) throw new Error('Failed to fetch friends');
    return response.json();
  },
  
  addFriend: async (name) => {
    const response = await fetch(`${API_BASE_URL}/friends`, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${getToken()}`
      },
      body: JSON.stringify({ name })
    });
    return response.json();
  },
  
  deleteFriend: async (id) => {
    const response = await fetch(`${API_BASE_URL}/friends/${id}`, {
      method: 'DELETE',
      headers: { 'Authorization': `Bearer ${getToken()}` }
    });
    return response.json();
  },
  
  // Meals
  addMeal: async (mealData) => {
    const response = await fetch(`${API_BASE_URL}/meals`, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${getToken()}`
      },
      body: JSON.stringify(mealData)
    });
    return response.json();
  },
  
  getMeals: async () => {
    const response = await fetch(`${API_BASE_URL}/meals`, {
      headers: { 'Authorization': `Bearer ${getToken()}` }
    });
    return response.json();
  },
  
  deleteMeal: async (id) => {
    const response = await fetch(`${API_BASE_URL}/meals/${id}`, {
      method: 'DELETE',
      headers: { 'Authorization': `Bearer ${getToken()}` }
    });
    return response.json();
  },
  
  // Balances
  getBalances: async () => {
    const response = await fetch(`${API_BASE_URL}/balances`, {
      headers: { 'Authorization': `Bearer ${getToken()}` }
    });
    return response.json();
  },
  
  // Settlements
  addSettlement: async (settlementData) => {
    const response = await fetch(`${API_BASE_URL}/settlements`, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${getToken()}`
      },
      body: JSON.stringify(settlementData)
    });
    return response.json();
  },
  
  getSettlements: async () => {
    const response = await fetch(`${API_BASE_URL}/settlements`, {
      headers: { 'Authorization': `Bearer ${getToken()}` }
    });
    return response.json();
  },
  
  confirmSettlement: async (id) => {
    const response = await fetch(`${API_BASE_URL}/settlements/${id}/confirm`, {
      method: 'PUT',
      headers: { 'Authorization': `Bearer ${getToken()}` }
    });
    return response.json();
  }
};

export default api;
